1	import React from "react";
2	import type { Phase, PhaseStatus, FreezeState } from "../../worker/types";
3	
4	const PHASE_STATUS_COLORS: Record<PhaseStatus, { bg: string; text: string }> = {
5	  DraftSpec:                { bg: "#f3f4f6", text: "#6b7280" },
6	  SpecApproved:             { bg: "#eff6ff", text: "#1d4ed8" },
7	  PRDAttached:              { bg: "#faf5ff", text: "#7c3aed" },
8	  ReadyForBuild:            { bg: "#ecfdf5", text: "#059669" },
9	  Accepted:                 { bg: "#dcfce7", text: "#16a34a" },
10	  ReworkRequired:           { bg: "#fff7ed", text: "#c2410c" },
11	  Closed:                   { bg: "#f3f4f6", text: "#9ca3af" },
12	};
13	
14	const PHASE_STATUS_LABELS: Record<PhaseStatus, string> = {
15	  DraftSpec:                "Draft Spec",
16	  SpecApproved:             "Spec Approved",
17	  PRDAttached:              "PRD Attached",
18	  ReadyForBuild:            "Ready for Build",
19	  Accepted:                 "Accepted",
20	  ReworkRequired:           "Rework Required",
21	  Closed:                   "Closed",
22	};
23	
24	const FREEZE_ICONS: Record<FreezeState, { icon: string; title: string; color: string }> = {
25	  Locked:                    { icon: "🔒", title: "Locked", color: "#dc2626" },
26	  FrozenDownstream:          { icon: "❄️", title: "Frozen Downstream", color: "#2563eb" },
27	  EditableDownstream:        { icon: "✏️", title: "Editable Downstream", color: "#16a34a" },
28	  DownstreamRevisionRequired:{ icon: "⚠️", title: "Downstream Revision Required", color: "#d97706" },
29	};
30	
31	interface PhaseListProps {
32	  phases: Phase[];
33	  selectedPhaseId?: string | null;
34	  onSelect: (phase: Phase) => void;
35	  onAdd: () => void;
36	  onDelete: (phaseId: string) => void;
37	  onReorder: (phaseId: string, direction: "up" | "down") => void;
38	  /** Map of phaseId → has spec */
39	  hasSpec?: Record<string, boolean>;
40	  /** Map of phaseId → has PRD */
41	  hasPRD?: Record<string, boolean>;
42	}
43	
44	export default function PhaseList({
45	  phases,
46	  selectedPhaseId,
47	  onSelect,
48	  onAdd,
49	  onDelete,
50	  onReorder,
51	  hasSpec = {},
52	  hasPRD = {},
53	}: PhaseListProps) {
54	  const sorted = [...phases].sort((a, b) => a.sortOrder - b.sortOrder);
55	
56	  return (
57	    <div style={{ fontFamily: "system-ui, sans-serif" }}>
58	      {/* Header row */}
59	      <div style={{
60	        display: "flex",
61	        justifyContent: "space-between",
62	        alignItems: "center",
63	        padding: "8px 16px 4px",
64	      }}>
65	        <span style={{ fontWeight: 600, fontSize: "13px", color: "#374151" }}>Phases</span>
66	        <button
67	          onClick={onAdd}
68	          style={{
69	            padding: "4px 12px",
70	            backgroundColor: "#2563eb",
71	            color: "#fff",
72	            border: "none",
73	            borderRadius: "6px",
74	            cursor: "pointer",
75	            fontSize: "12px",
76	            fontWeight: 500,
77	          }}
78	        >
79	          + Add Phase
80	        </button>
81	      </div>
82	
83	      {sorted.length === 0 ? (
84	        <div style={{ padding: "24px 16px", textAlign: "center", color: "#9ca3af", fontSize: "14px" }}>
85	          No phases yet. Click "Add Phase" to get started.
86	        </div>
87	      ) : (
88	        <div style={{ padding: "4px 16px 12px" }}>
89	          {sorted.map((phase, index) => {
90	            const isSelected = phase.id === selectedPhaseId;
91	            const freezeInfo = FREEZE_ICONS[phase.freezeState];
92	            const statusColors = PHASE_STATUS_COLORS[phase.status];
93	            const specPresent = hasSpec[phase.id];
94	            const prdPresent = hasPRD[phase.id];
95	
96	            return (
97	              <div
98	                key={phase.id}
99	                onClick={() => onSelect(phase)}
100	                style={{
101	                  padding: "10px 12px",
102	                  border: `1px solid ${isSelected ? "#2563eb" : "#e5e7eb"}`,
103	                  borderRadius: "8px",
104	                  marginBottom: "6px",
105	                  backgroundColor: isSelected ? "#eff6ff" : "#fff",
106	                  cursor: "pointer",
107	                  display: "flex",
108	                  alignItems: "center",
109	                  gap: "10px",
110	                }}
111	                onMouseEnter={(e) => {
112	                  if (!isSelected) e.currentTarget.style.borderColor = "#93c5fd";
113	                }}
114	                onMouseLeave={(e) => {
115	                  if (!isSelected) e.currentTarget.style.borderColor = "#e5e7eb";
116	                }}
117	              >
118	                {/* Phase number */}
119	                <span style={{
120	                  minWidth: "26px",
121	                  height: "26px",
122	                  borderRadius: "50%",
123	                  backgroundColor: isSelected ? "#2563eb" : "#e5e7eb",
124	                  color: isSelected ? "#fff" : "#374151",
125	                  display: "flex",
126	                  alignItems: "center",
127	                  justifyContent: "center",
128	                  fontSize: "12px",
129	                  fontWeight: 700,
130	                  flexShrink: 0,
131	                }}>
132	                  {phase.phaseNumber}
133	                </span>
134	
135	                {/* Title + badges */}
136	                <div style={{ flex: 1, minWidth: 0 }}>
137	                  <div style={{ display: "flex", alignItems: "center", gap: "6px", flexWrap: "wrap" }}>
138	                    <span style={{ fontWeight: 600, fontSize: "13px", color: "#111827" }}>
139	                      {phase.title || "Untitled Phase"}
140	                    </span>
141	                    {/* Status badge */}
142	                    <span style={{
143	                      fontSize: "11px",
144	                      padding: "1px 7px",
145	                      borderRadius: "10px",
146	                      backgroundColor: statusColors.bg,
147	                      color: statusColors.text,
148	                      fontWeight: 500,
149	                      whiteSpace: "nowrap",
150	                    }}>
151	                      {PHASE_STATUS_LABELS[phase.status]}
152	                    </span>
153	                    {/* Freeze indicator */}
154	                    <span
155	                      title={freezeInfo.title}
156	                      style={{ fontSize: "13px", cursor: "default" }}
157	                    >
158	                      {freezeInfo.icon}
159	                    </span>
160	                    {/* Spec icon */}
161	                    {specPresent && (
162	                      <span
163	                        title="Spec attached"
164	                        style={{ fontSize: "11px", padding: "1px 6px", borderRadius: "10px", backgroundColor: "#eff6ff", color: "#1d4ed8", fontWeight: 500 }}
165	                      >
166	                        Spec
167	                      </span>
168	                    )}
169	                    {/* PRD icon */}
170	                    {prdPresent && (
171	                      <span
172	                        title="PRD attached"
173	                        style={{ fontSize: "11px", padding: "1px 6px", borderRadius: "10px", backgroundColor: "#faf5ff", color: "#7c3aed", fontWeight: 500 }}
174	                      >
175	                        PRD
176	                      </span>
177	                    )}
178	                  </div>
179	                </div>
180	
181	                {/* Reorder + delete controls */}
182	                <div
183	                  style={{ display: "flex", alignItems: "center", gap: "2px", flexShrink: 0 }}
184	                  onClick={(e) => e.stopPropagation()}
185	                >
186	                  <button
187	                    disabled={index === 0}
188	                    onClick={() => onReorder(phase.id, "up")}
189	                    title="Move up"
190	                    style={{
191	                      background: "none",
192	                      border: "none",
193	                      cursor: index === 0 ? "default" : "pointer",
194	                      color: index === 0 ? "#d1d5db" : "#6b7280",
195	                      fontSize: "14px",
196	                      padding: "2px 4px",
197	                      lineHeight: 1,
198	                    }}
199	                  >
200	                    ▲
201	                  </button>
202	                  <button
203	                    disabled={index === sorted.length - 1}
204	                    onClick={() => onReorder(phase.id, "down")}
205	                    title="Move down"
206	                    style={{
207	                      background: "none",
208	                      border: "none",
209	                      cursor: index === sorted.length - 1 ? "default" : "pointer",
210	                      color: index === sorted.length - 1 ? "#d1d5db" : "#6b7280",
211	                      fontSize: "14px",
212	                      padding: "2px 4px",
213	                      lineHeight: 1,
214	                    }}
215	                  >
216	                    ▼
217	                  </button>
218	                  <button
219	                    onClick={() => onDelete(phase.id)}
