  color: "#9ca3af",
  fontStyle: "italic",
};

interface PhaseDetailProps {
  phase: Phase;
  spec: Spec | null;
  prd: PRD | null;
  onSave: (updates: Partial<Phase>) => void;
  onCancel: () => void;
}

export default function PhaseDetail({ phase, spec, prd, onSave, onCancel }: PhaseDetailProps) {
  const [draft, setDraft] = useState<Phase>({ ...phase });
