      backgroundColor: colors.bg,
      color: colors.text,
    }}>
      {status}
    </span>
  );
}

function PhaseList({ phases }: { phases: Phase[] }) {
  if (phases.length === 0) {
    return (
      <div style={{ padding: "24px", textAlign: "center", color: "#9ca3af", fontSize: "14px" }}>
        No phases yet. Add a phase to get started.
      </div>
    );
  }

  return (
